1	export interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	const PROCESSING_FEE = 5;
9	const FIRST_INSURANCE_SURCHARGE = 1.1;
10	const RETURNING_CUSTOMER_DISCOUNT = 0.85;
11	
12	function contractMultiplierFor(previousContracts: number | undefined): number {
13	  return (previousContracts ?? 0) >= 1 ? RETURNING_CUSTOMER_DISCOUNT : FIRST_INSURANCE_SURCHARGE;
14	}
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const COMPONENT_BUNDLE_BASE = 60;
26	const COMPONENT_BUNDLE_SIZE = 3;
27	const BUNDLEABLE_COMPONENTS = new Set(["rune", "moonstone"]);
28	
29	function roundUpToWholeG(amount: number): number {
30	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
31	  return Math.ceil(Math.round(amount * 100) / 100);
32	}
33	
34	const CURSED_SURCHARGE = 1.5;
35	const HIGH_ENCHANTMENT_SURCHARGE = 1.3;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	
38	const LOYALTY_DISCOUNT = 0.8;
39	const LOYALTY_YEARS_THRESHOLD = 2;
40	
41	function loyaltyDiscountFor(customer: { yearsWithMHPCO: number }): number {
42	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 1;
43	}
44	
45	function isHighlyEnchanted(item: Item): boolean {
46	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
47	}
48	
49	function riskMultiplier(item: Item): number {
50	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE : 1;
51	  const enchantmentMultiplier = isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 1;
52	  return cursedMultiplier * enchantmentMultiplier;
53	}
54	
55	function premiumFor(item: Item, loyaltyDiscount: number, contractMultiplier: number): number {
56	  const basePremium = BASE_PREMIUMS[item.type];
57	  return roundUpToWholeG(basePremium * riskMultiplier(item) * loyaltyDiscount * contractMultiplier);
58	}
59	
60	function isThreeAlikeBundle(items: Item[]): boolean {
61	  if (items.length !== COMPONENT_BUNDLE_SIZE) return false;
62	  const firstType = items[0].type;
63	  return (
64	    BUNDLEABLE_COMPONENTS.has(firstType) &&
65	    items.every((item) => item.type === firstType)
66	  );
67	}
68	
69	function bundlePremium(contractMultiplier: number): number {
70	  return roundUpToWholeG(COMPONENT_BUNDLE_BASE * contractMultiplier);
71	}
72	
73	export function quote(
74	  customer: { yearsWithMHPCO: number },
75	  items: Item[],
76	  previousContracts?: number,
77	): number {
78	  const loyaltyDiscount = loyaltyDiscountFor(customer);
79	  const contractMultiplier = contractMultiplierFor(previousContracts);
80	  const itemsTotal = isThreeAlikeBundle(items)
81	    ? bundlePremium(contractMultiplier)
82	    : items.reduce((sum, item) => sum + premiumFor(item, loyaltyDiscount, contractMultiplier), 0);
83	  return itemsTotal + PROCESSING_FEE;
84	}
85	
86	export interface Damage {
87	  itemType: string;
88	  amount: number;
89	}
90	
91	export interface Incident {
92	  cause: string;
93	  damages: Damage[];
94	}
95	
96	const CLAIM_DEDUCTIBLE = 100;
97	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
98	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
99	
100	function qualifiesForHighEnchantmentClaim(item: Item | undefined): boolean {
101	  return item !== undefined && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
102	}
103	
104	function reimbursementFor(damage: Damage, policyItems: Item[]): number {
105	  const item = policyItems.find((i) => i.type === damage.itemType);
106	  if (item?.material === "dragon") return damage.amount;
107	  return qualifiesForHighEnchantmentClaim(item)
108	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
109	    : 0;
110	}
111	
112	export function claim(
113	  policyItems: Item[],
114	  incident: Incident,
115	): number {
116	  const reimbursement = incident.damages.reduce(
117	    (sum, damage) => sum + reimbursementFor(damage, policyItems),
118	    0,
119	  );
120	  if (reimbursement === 0) return 0;
121	  return reimbursement - CLAIM_DEDUCTIBLE;
122	}
